package main

import (
    "encoding/json"
    "fmt"
)

type Product struct {
    ID    int     `json:"id"`
    Name  string  `json:"name"`
    Price float64 `json:"price,omitempty"`
    Tags  []string `json:"tags,omitempty"`
}

func main() {
    // Marshal
    p := Product{ID: 1, Name: "Widget", Price: 9.99, Tags: []string{"sale", "new"}}
    data, _ := json.MarshalIndent(p, "", "  ")
    fmt.Println(string(data))

    // Unmarshal
    jsonStr := `{"id":2,"name":"Gadget","tags":["popular"]}`
    var p2 Product
    json.Unmarshal([]byte(jsonStr), &p2)
    fmt.Printf("%+v\n", p2)
}
